  ('diplomatic-9e854390-moex-00522', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-110-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '大陸地區人民在臺灣地區設有戶籍滿幾年，才可以登記為公職候選人？', '["5年", "10年", "15年", "20年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:32+00:00", "source_pdf_sha1": "feacf0daac2e", "answer_pdf_sha1": "4af45c9595a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
